/* ============================================================
   Streamer Showcase — filter, render, live status
   ============================================================ */

/* -- Live status -------------------------------------------- */
/* Reads from live-status.json, generated by GitHub Actions.   */
/* Format: { "twitch_login": true, ... }                       */

let liveStatus = {};

async function fetchLiveStatus() {
  try {
    const res = await fetch('live-status.json?t=' + Date.now());
    if (res.ok) liveStatus = await res.json();
  } catch (_) {
    /* file may not exist yet — silently ignore */
  }
}

/* -- Rendering --------------------------------------------- */

function langLabel(code) {
  const map = { en: 'EN', fr: 'FR', de: 'DE', es: 'ES', zh: 'ZH', ru: 'RU', pt: 'PT' };
  return map[code] || code.toUpperCase();
}

function buildCard(s) {
  const isLive = s.twitch && liveStatus[s.twitch.toLowerCase()];

  const TAG_LABELS = {
    'cam-on':        'Cam On',
    'no-cam':        'No Cam',
    'tryharder':     'Tryharder',
    'entertainer':   'Entertainer',
    'casual-player': 'Casual Player',
    'operation':     'Operation',
    'warfare':       'Warfare',
    'top-player':    'Top Player',
    'sineva':        'Sineva',
    'girl':          'Girl'
  };

  const tagPills = s.tags
    .map(t => `<span class="tag-pill" data-tag="${t}">${TAG_LABELS[t] || t}</span>`)
    .join('');

  const twitchBtn = s.twitch
    ? `<a href="https://twitch.tv/${s.twitch}" class="btn-platform btn-twitch" target="_blank" rel="noopener">Twitch</a>`
    : '';

  const youtubeBtn = s.youtube
    ? `<a href="${s.youtube}" class="btn-platform btn-youtube" target="_blank" rel="noopener">YouTube</a>`
    : '';

  const liveBadge = isLive
    ? `<span class="live-badge" aria-label="Currently live"><span class="live-dot"></span>LIVE</span>`
    : '';

  return `
    <article class="streamer-card" data-tags="${s.tags.join(',')}" data-lang="${s.lang}">
      <div class="streamer-card__top">
        <span class="streamer-card__name">${s.name}</span>
        <span class="streamer-card__lang">${langLabel(s.lang)}</span>
        ${liveBadge}
      </div>
      <p class="streamer-card__note">${s.desc}</p>
      <div class="streamer-card__tags">${tagPills}</div>
      <div class="streamer-card__footer">${twitchBtn}${youtubeBtn}</div>
    </article>
  `;
}

/* -- Filter logic ------------------------------------------ */

let activeTag = 'all';
let activeLang = 'all';
let searchQuery = '';

function applyFilters() {
  const q = searchQuery.toLowerCase();

  const visible = STREAMERS.filter(s => {
    const matchTag  = activeTag === 'all' || s.tags.includes(activeTag);
    const matchLang = activeLang === 'all' || s.lang === activeLang;
    const matchName = !q || s.name.toLowerCase().includes(q);
    return matchTag && matchLang && matchName;
  });

  const grid  = document.getElementById('streamers-grid');
  const empty = document.getElementById('empty-state');
  const count = document.getElementById('filter-count');

  grid.innerHTML = visible.map(buildCard).join('');
  empty.hidden   = visible.length > 0;
  count.textContent = visible.length === STREAMERS.length
    ? `${STREAMERS.length} streamers`
    : `${visible.length} of ${STREAMERS.length} streamers`;
}

/* -- Boot -------------------------------------------------- */

(async () => {
  await fetchLiveStatus();
  applyFilters();

  /* Tag buttons */
  document.querySelectorAll('.tag-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tag-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      activeTag = btn.dataset.tag;
      applyFilters();
    });
  });

  /* Language select */
  const langSelect = document.getElementById('lang-filter');
  if (langSelect) {
    langSelect.addEventListener('change', () => {
      activeLang = langSelect.value;
      applyFilters();
    });
  }

  /* Search */
  const searchInput = document.getElementById('streamer-search');
  if (searchInput) {
    searchInput.addEventListener('input', () => {
      searchQuery = searchInput.value;
      applyFilters();
    });
  }
})();
